import { useState, useCallback, useEffect, useRef } from "react";

// ── SYNC LAYER ────────────────────────────────────────────────────────────
// This is the ONE file used both for local preview (here in chat) and for
// real deployment (Vercel). It never hard-imports the firebase package at
// the top level — a static `import "firebase/..."` would make this file
// fail to load entirely in any environment that doesn't have that package
// available (like this artifact preview sandbox). Instead, Firebase is
// loaded dynamically at runtime, and if that fails for any reason, a
// localStorage-backed fallback with the identical function shape takes
// over automatically. Same file, same behavior contract, no manual sync
// between a "real" version and a "preview" version ever again.
let _fsdoc, _fssetDoc, _fsonSnapshot, _fsdb;
let _usingFirebase = false;

const _listeners = {};
function _localDoc(_db, _collection, id) { return { _key: "local_" + id }; }
function _localSetDoc(ref, data) {
  try { localStorage.setItem(ref._key, JSON.stringify(data)); } catch {}
  (_listeners[ref._key] || []).forEach(cb => cb({ data: () => data }));
  return Promise.resolve();
}
function _localOnSnapshot(ref, cb) {
  if (!_listeners[ref._key]) _listeners[ref._key] = [];
  _listeners[ref._key].push(cb);
  try {
    const raw = localStorage.getItem(ref._key);
    cb({ data: () => (raw ? JSON.parse(raw) : undefined) });
  } catch { cb({ data: () => undefined }); }
  return () => { _listeners[ref._key] = (_listeners[ref._key] || []).filter(f => f !== cb); };
}

