let _uid = 1;
const uid = () => _uid++;

function initPlayer(name, joinOrder) {
  return { id: uid(), name, joinOrder, roundsWaited: 0, gamesPlayed: 0, wins: 0, winStreak: 0, hasPlayed: false, streakedOut: false, injurySubGame: false, isGuest: false };
}

function sortQueue(players) {
  const experienced = players.filter(p => p.hasPlayed);
  const avg = experienced.length > 0 ? experienced.reduce((s, p) => s + (p.gamesPlayed || 0), 0) / experienced.length : 0;
  const maxWait = experienced.length > 0 ? Math.max(...experienced.map(p => p.roundsWaited)) : 0;
  const eff = (p) => p.roundsWaited + Math.min(Math.max(avg - (p.gamesPlayed || 0), 0), maxWait);
  const seed = (p) => (p.id * 2654435761 % 2147483647) / 2147483647;
  return [...players].sort((a, b) => {
    const aN = !a.hasPlayed, bN = !b.hasPlayed;
    if (aN && !bN) return -1; if (!aN && bN) return 1;
    if (aN && bN) return a.joinOrder - b.joinOrder;
    const ea = eff(a), eb = eff(b);
    if (eb !== ea) return eb - ea;
    // Tie on effective wait: genuine waiting beats a catch-up boost.
    // Raw roundsWaited decides first, so a capped-boost latecomer can
    // tie but never leapfrog someone who actually stood in line.
    if (b.roundsWaited !== a.roundsWaited) return b.roundsWaited - a.roundsWaited;
    if ((a.gamesPlayed || 0) !== (b.gamesPlayed || 0)) return (a.gamesPlayed || 0) - (b.gamesPlayed || 0);
    return seed(a) - seed(b);
  });
}

function pickNextTeam(pool, teamSize) {
  const s = sortQueue(pool);
  return { nextTeam: s.slice(0, teamSize).map(p => ({ ...p, hasPlayed: true })), bench: s.slice(teamSize) };
}

// Roster chip helpers — initials + a stable color per name
function nameInitials(name) {
  const parts = name.replace(/^(Pastor|Dr|Mr|Mrs|Ms)\s+/i, "").trim().split(/\s+/);
  return (parts[0][0] + (parts[1] ? parts[1][0] : "")).toUpperCase();
}
function nameHue(name) {
  let h = 0;
  for (let i = 0; i < name.length; i++) h = (h * 31 + name.charCodeAt(i)) % 360;
  return h;
}

// Wait-time heat scale — hotter = waited longer. Reads the live COLOR
// reference so it automatically produces a dark-safe palette when dark
// mode is active, rather than hardcoded light-only pastels that would
// otherwise trap light-mode-only backgrounds under dark-mode text.
function waitHeat(roundsWaited) {
  const w = roundsWaited || 0;
  const dark = COLOR === COLOR_DARK;
  if (w >= 4) return dark ? { background: "#4A2320", color: "#FF8A80" } : { background: "#FFE5E0", color: "#D32F2F" };
  if (w === 3) return dark ? { background: "#4A2E10", color: "#FFB74D" } : { background: "#FFF0E0", color: "#E65100" };
  if (w === 2) return dark ? { background: "#4A3D10", color: "#FFE082" } : { background: "#FFF8E0", color: "#F9A825" };
  if (w === 1) return dark ? { background: "#10304A", color: "#64B5F6" } : { background: "#F0F7FF", color: "#007AFF" };
  return { background: "transparent", color: COLOR.secondaryLabel };
}

// Queue-position heat — only the next teamSize players (who play the very
// next game) are highlighted; everyone else is neutral.
function positionHeat(pos, teamSize) {
  const dark = COLOR === COLOR_DARK;
  if (pos <= teamSize) return dark ? { background: "#4A2320", color: "#FF8A80" } : { background: "#FFE5E0", color: "#D32F2F" };
  return { background: "transparent", color: COLOR.secondaryLabel };
}

